rows = []
with open("questions.csv", encoding="utf-8") as f:
    reader = csv.reader(f)
    for row in reader:
        if len(row) >= 9:
            q_id = row[0]
            if q_id in fixes:
                row[4] = fixes[q_id][0]
                row[5] = fixes[q_id][1]
                row[6] = fixes[q_id][2]
                row[7] = fixes[q_id][3]
                row[8] = fixes[q_id][4]
        rows.append(row)

with open("questions.csv", "w", encoding="utf-8", newline="") as f:
    writer = csv.writer(f)
    writer.writerows(rows)

print("Updates applied.")
